import '../lib/minor_units.dart';
import '../lib/proportional_allocator.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  check(MinorUnits.parse('9007199254740993.01') == 900719925474099301,
      'amounts beyond binary floating-point precision remain exact');
  check(MinorUnits.parse('+0.0007', scale: 4) == 7,
      'an explicit sign and leading fractional zeroes are preserved');

  final credit = ProportionalAllocator().allocate(-5, [1, 1, 1]);
  check(credit[0] == -2 && credit[1] == -2 && credit[2] == -1,
      'negative totals distribute magnitude with the same stable ordering');
  check(credit.reduce((left, right) => left + right) == -5,
      'a distributed credit exactly preserves its signed total');

  final sparse = ProportionalAllocator().allocate(-7, [0, 2, 1]);
  check(sparse[0] == 0 && sparse[1] == -5 && sparse[2] == -2,
      'zero-weight entries remain zero during negative allocation');
}
